import React from "react";

export default function HomeScreen({
  balance,
  onDeposit,
  onWithdraw,
  onHistory,
  onAddMoneyOptions,
}) {
  return (
    <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24 flex flex-col gap-6">
      {/* Header */}
      <h1 className="text-xl font-semibold text-gray-900">Welcome</h1>

      {/* Balance */}
      <p className="text-gray-500">Balance: ₦{balance.toLocaleString()}</p>

      {/* Actions */}
      <button
        onClick={onDeposit}
        className="w-full bg-emerald-600 text-white py-4 rounded-xl font-semibold active:scale-[0.98] transition"
      >
        Deposit
      </button>

      <button
        onClick={onWithdraw}
        className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition"
      >
        Withdraw
      </button>

      <button
        onClick={onHistory}
        className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition"
      >
        Transaction History
      </button>

      <button
        onClick={onAddMoneyOptions}
        className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition"
      >
        Add Money
      </button>
    </div>
  );
}
